function checkIsT320() {
  if (typeof window === 'undefined') return false;
  var iw = window.innerWidth || 0;
  var sw = window.screen ? window.screen.width : 0;
  var isCapacitor = !!(window.Capacitor && window.Capacitor.isNativePlatform && window.Capacitor.isNativePlatform());
  if (iw <= 280 || sw <= 280) return true;
  if (isCapacitor && (iw <= 480 || sw <= 480)) return true;
  return false;
}

function useIsT320() {
  var val = useState(checkIsT320);
  var isT320 = val[0];
  var setIsT320 = val[1];
  useEffect(function() {
    var handler = function() { setIsT320(checkIsT320()); };
    window.addEventListener('resize', handler);
    return function() { window.removeEventListener('resize', handler); };
  }, []);
  return isT320;
}

const STATUS_LABELS = {
  'off_duty': 'OFF DUTY',
  'on_duty': 'ON DUTY',
  'en_route': 'EN ROUTE',
  'arrived': 'ARRIVED',
  'oos': 'OOS',
  'out_of_service': 'OOS',
};

const STATUS_CYCLE = ['off_duty', 'on_duty', 'en_route', 'arrived', 'oos'];

function formatStatus(status) {
  return STATUS_LABELS[status?.toLowerCase()] || status?.toUpperCase()?.replace(/_/g, ' ') || 'UNKNOWN';
}

function getNextStatus(currentStatus) {
  const currentIndex = STATUS_CYCLE.indexOf(currentStatus?.toLowerCase());
  const nextIndex = (currentIndex + 1) % STATUS_CYCLE.length;
  return STATUS_CYCLE[nextIndex];
}

